+                    match client.create(&req) {
+                        Ok(_) => successes += 1,
+                        Err(e) => {
+                            failures += 1;
+                            // Verify error is "clean" (not corruption)
+                            let err = e.to_string().to_lowercase();
+                            assert!(
+                                !err.contains("corrupt") && !err.contains("malformed"),
+                                "Got corruption error in thread {}: {}",
