+                "Database corrupted after concurrent writes: {}",
+                e
+            );
+            log.warn("VERIFY", &format!("List failed (not corruption): {}", e), None);
+        }
+    }
+
+    log.success("PASS", "No corruption from concurrent writes", None);
+}
