+                    log.info(
+                        "RESULT",
+                        &format!("Got non-corruption error: {}", e),
+                        None,
+                    );
+                }
+            }
+
+            // Kill the lock holder
+            let _ = child.kill();
+            let _ = child.wait();
+            log.info("LOCK", "Lock holder terminated", None);
